          <nav className="flex bg-gray-100 p-1 rounded-lg overflow-x-auto">
            {[
              { id: 'reporting', label: 'Incidents' },
              { id: 'configuration', label: 'Infra' },
              { id: 'team', label: 'Team' },
              { id: 'audit', label: 'Audit' }
