const API_BASE = '/api';

const TOKEN_KEY = 'voximplant_status_token';

const getHeaders = (skipAuth = false) => {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };
  if (!skipAuth) {
    const token = localStorage.getItem(TOKEN_KEY);
    if (token) headers['Authorization'] = `Bearer ${token}`;
  }
  return headers;
};

export const api = {
  async getStatus() {
    const res = await fetch(`${API_BASE}/status`);
    if (!res.ok) throw new Error('Failed to fetch status');
    return res.json();
  },

  async login(credentials: any) {
    const res = await fetch(`${API_BASE}/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(credentials),
    });
    if (!res.ok) throw new Error('Invalid credentials');
    return res.json();
  },

  async getAdminData() {
    const res = await fetch(`${API_BASE}/admin/data`, { headers: getHeaders() });
    if (!res.ok) throw new Error('Failed to fetch admin data');
    return res.json();
  },

  async createUser(user: any) {
    const res = await fetch(`${API_BASE}/admin/users`, { method: 'POST', headers: getHeaders(), body: JSON.stringify(user) });
    return res.json();
  },

  async deleteUser(id: string) {
    const res = await fetch(`${API_BASE}/admin/users/${id}`, { method: 'DELETE', headers: getHeaders() });
    return res.json();
  },

  async createRegion(name: string) {
    const res = await fetch(`${API_BASE}/admin/regions`, { method: 'POST', headers: getHeaders(), body: JSON.stringify({ name }) });
    return res.json();
  },

  async deleteRegion(id: string) {
    const res = await fetch(`${API_BASE}/admin/regions/${id}`, { method: 'DELETE', headers: getHeaders() });
    return res.json();
  },

  async createService(regionId: string, name: string, description: string) {
    const res = await fetch(`${API_BASE}/admin/services`, { method: 'POST', headers: getHeaders(), body: JSON.stringify({ regionId, name, description }) });
    return res.json();
  },

  async deleteService(id: string) {
    const res = await fetch(`${API_BASE}/admin/services/${id}`, { method: 'DELETE', headers: getHeaders() });
    return res.json();
  },

  async createComponent(serviceId: string, name: string, description: string) {
    const res = await fetch(`${API_BASE}/admin/components`, { method: 'POST', headers: getHeaders(), body: JSON.stringify({ serviceId, name, description }) });
    return res.json();
  },

  async deleteComponent(id: string) {
    const res = await fetch(`${API_BASE}/admin/components/${id}`, { method: 'DELETE', headers: getHeaders() });
    return res.json();
  },

  async createIncident(incident: any) {
    const res = await fetch(`${API_BASE}/admin/incidents`, { method: 'POST', headers: getHeaders(), body: JSON.stringify(incident) });
    return res.json();
  },

  async updateIncident(id: string, incident: any) {
    const res = await fetch(`${API_BASE}/admin/incidents/${id}`, { method: 'PUT', headers: getHeaders(), body: JSON.stringify(incident) });
    if (!res.ok) throw new Error('Failed to update incident');
    return res.json();
  },

  async resolveIncident(id: string) {
    const res = await fetch(`${API_BASE}/admin/incidents/${id}/resolve`, { method: 'POST', headers: getHeaders() });
    return res.json();
  }
};

import React, { createContext, useContext, useState, useEffect, useCallback, useMemo } from 'react';
import { AppState, Severity, AdminUser, AuditLog, Incident } from './types.ts';
import { api } from './services/api.ts';

interface AppContextType {
  state: AppState;
  isLoading: boolean;
  addRegion: (name: string) => Promise<void>;
  removeRegion: (id: string) => Promise<void>;
  addService: (regionId: string, name: string, description: string) => Promise<void>;
  removeService: (id: string) => Promise<void>;
  addComponent: (serviceId: string, name: string, description: string) => Promise<void>;
  removeComponent: (id: string) => Promise<void>;
  reportIncident: (incident: any) => Promise<void>;
  updateIncident: (id: string, incident: any) => Promise<void>;
  resolveIncident: (incidentId: string) => Promise<void>;
  createAdmin: (user: any) => Promise<void>;
  deleteAdmin: (id: string) => Promise<void>;
  login: (credentials: any) => Promise<void>;
  logout: () => void;
  fetchAdminData: () => Promise<void>;
  calculateSLA: (componentId: string, days?: number) => number;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const TOKEN_KEY = 'voximplant_status_token';
const USER_KEY = 'voximplant_status_user';

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>({
    regions: [],
    services: [],
    components: [],
    incidents: [],
    users: [],
    auditLogs: [],
    isAuthenticated: !!localStorage.getItem(TOKEN_KEY),
    currentUser: localStorage.getItem(USER_KEY) || undefined,
  });
  const [isLoading, setIsLoading] = useState(true);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await api.getStatus();
      setState(prev => ({ ...prev, ...data }));
    } catch (err) {
      console.error("Failed to fetch status map", err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const fetchAdminData = useCallback(async () => {
    if (!state.isAuthenticated) return;
    try {
      const data = await api.getAdminData();
      setState(prev => ({ ...prev, ...data }));
    } catch (err) {
      console.error("Failed to fetch admin info", err);
    }
  }, [state.isAuthenticated]);

  useEffect(() => {
    fetchData();
    if (state.isAuthenticated) fetchAdminData();
  }, [fetchData, fetchAdminData, state.isAuthenticated]);

  const addRegion = async (name: string) => { await api.createRegion(name); fetchData(); fetchAdminData(); };
  const removeRegion = async (id: string) => { await api.deleteRegion(id); fetchData(); fetchAdminData(); };
  const addService = async (rid: string, n: string, d: string) => { await api.createService(rid, n, d); fetchData(); fetchAdminData(); };
  const removeService = async (id: string) => { await api.deleteService(id); fetchData(); fetchAdminData(); };
  const addComponent = async (sid: string, n: string, d: string) => { await api.createComponent(sid, n, d); fetchData(); fetchAdminData(); };
  const removeComponent = async (id: string) => { await api.deleteComponent(id); fetchData(); fetchAdminData(); };

  const reportIncident = async (inc: any) => { await api.createIncident(inc); fetchData(); fetchAdminData(); };
  const updateIncident = async (id: string, inc: any) => { await api.updateIncident(id, inc); fetchData(); fetchAdminData(); };
  const resolveIncident = async (id: string) => { await api.resolveIncident(id); fetchData(); fetchAdminData(); };

  const createAdmin = async (u: any) => { await api.createUser(u); fetchAdminData(); };
  const deleteAdmin = async (id: string) => { await api.deleteUser(id); fetchAdminData(); };

  const login = async (cred: any) => {
    const { token, username } = await api.login(cred);
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(USER_KEY, username);
    setState(prev => ({ ...prev, isAuthenticated: true, currentUser: username }));
    fetchData();
    fetchAdminData();
  };

  const logout = () => {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
    setState(prev => ({ ...prev, isAuthenticated: false, currentUser: undefined }));
  };

  const calculateSLA = useCallback((componentId: string, days = 90) => {
    const now = Date.now();
    const periodStart = now - (days * 24 * 60 * 60 * 1000);
    const totalMinutes = days * 24 * 60;

    const componentIncidents = state.incidents.filter(i => i.componentId === componentId);
    let totalDowntimeMinutes = 0;

    componentIncidents.forEach(inc => {
      const incStart = Math.max(new Date(inc.startTime).getTime(), periodStart);
      const incEnd = inc.endTime ? new Date(inc.endTime).getTime() : now;

      if (incEnd > periodStart) {
        const durationMs = incEnd - incStart;
        if (durationMs > 0) {
          const durationMinutes = durationMs / (1000 * 60);
          // Outage is 100% impact, Degraded is 50% impact for SLA purposes
          const impactFactor = inc.severity === Severity.OUTAGE ? 1 : 0.5;
          totalDowntimeMinutes += durationMinutes * impactFactor;
        }
      }
    });

    const availability = ((totalMinutes - totalDowntimeMinutes) / totalMinutes) * 100;
    return Math.max(0, Math.min(100, parseFloat(availability.toFixed(3))));
  }, [state.incidents]);

  return (
    <AppContext.Provider value={{
      state, isLoading, addRegion, removeRegion, addService, 
      removeService, addComponent, removeComponent,
      reportIncident, updateIncident, resolveIncident, createAdmin, deleteAdmin, login, logout, fetchAdminData,
      calculateSLA
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import React from 'react';
import { useApp } from '../store.tsx';
import { Severity } from '../types.ts';
import UptimeGraph from './UptimeGraph.tsx';

const PublicDashboard: React.FC = () => {
  const { state, calculateSLA } = useApp();

  const getComponentStatus = (componentId: string) => {
    const activeIncidents = state.incidents.filter(i => i.componentId === componentId && !i.endTime);
    if (activeIncidents.find(i => i.severity === Severity.OUTAGE)) return Severity.OUTAGE;
    if (activeIncidents.find(i => i.severity === Severity.DEGRADED)) return Severity.DEGRADED;
    return Severity.OPERATIONAL;
  };

  const getServiceStatus = (serviceId: string) => {
    const componentIds = state.components.filter(c => c.serviceId === serviceId).map(c => c.id);
    if (componentIds.length === 0) return Severity.OPERATIONAL;
    const statuses = componentIds.map(getComponentStatus);
    if (statuses.includes(Severity.OUTAGE)) return Severity.OUTAGE;
    if (statuses.includes(Severity.DEGRADED)) return Severity.DEGRADED;
    return Severity.OPERATIONAL;
  };

  const globalStatus = React.useMemo(() => {
    if (state.components.length === 0) return { label: 'System Initializing', color: 'bg-indigo-500', sub: 'Monitoring is starting up...' };
    const statuses = state.components.map(c => getComponentStatus(c.id));
    if (statuses.includes(Severity.OUTAGE)) return { label: 'System Outage', color: 'bg-red-600', sub: 'Major disruptions are occurring' };
    if (statuses.includes(Severity.DEGRADED)) return { label: 'Partial Degradation', color: 'bg-yellow-500', sub: 'Some services are experiencing issues' };
    return { label: 'All Systems Operational', color: 'bg-emerald-500', sub: 'Services are running optimally' };
  }, [state]);

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <div className={`${globalStatus.color} rounded-xl p-8 text-white shadow-lg mb-12 transition-all duration-500`}>
        <h1 className="text-3xl font-bold mb-2">{globalStatus.label}</h1>
        <p className="opacity-90">{globalStatus.sub}</p>
      </div>

      {state.incidents.filter(i => !i.endTime).length > 0 && (
        <div className="mb-12">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></span>
            Active Incidents
          </h2>
          <div className="space-y-4">
            {state.incidents.filter(i => !i.endTime).map(incident => (
              <div key={incident.id} className="bg-white border-l-4 border-red-500 rounded-lg p-6 shadow-sm animate-in fade-in slide-in-from-top-2">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-lg">{incident.title}</h3>
                  <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                    incident.severity === Severity.OUTAGE ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'
                  }`}>
                    {incident.severity}
                  </span>
                </div>
                <p className="text-gray-600 mb-4">{incident.description}</p>
                <div className="text-xs text-gray-400">
                  Detected: {new Date(incident.startTime).toLocaleString()}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="space-y-12">
        {state.regions.map(region => (
          <div key={region.id}>
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-[0.2em] mb-6 border-b pb-2">{region.name}</h2>
            <div className="space-y-8">
              {state.services.filter(s => s.regionId === region.id).map(service => {
                const serviceStatus = getServiceStatus(service.id);
                return (
                  <div key={service.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                    <div className="p-4 bg-gray-50 flex justify-between items-center border-b border-gray-100">
                      <div>
                        <h3 className="font-bold text-gray-700">{service.name}</h3>
                        <p className="text-[10px] text-gray-400 uppercase font-bold">{service.description}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <span className={`text-xs font-bold uppercase ${
                          serviceStatus === Severity.OPERATIONAL ? 'text-emerald-500' :
                          serviceStatus === Severity.DEGRADED ? 'text-yellow-600' : 'text-red-600'
                        }`}>
                          {serviceStatus}
                        </span>
                        <div className={`w-2 h-2 rounded-full ${
                          serviceStatus === Severity.OPERATIONAL ? 'bg-emerald-500' :
                          serviceStatus === Severity.DEGRADED ? 'bg-yellow-500' : 'bg-red-500'
                        }`}></div>
                      </div>
                    </div>
                    <div className="divide-y divide-gray-50">
                      {state.components.filter(c => c.serviceId === service.id).map(comp => {
                        const compStatus = getComponentStatus(comp.id);
                        const sla = calculateSLA(comp.id);
                        return (
                          <div key={comp.id} className="p-6 hover:bg-gray-50 transition-colors">
                            <div className="flex justify-between items-center mb-3">
                              <div>
                                <h4 className="font-semibold text-gray-800 text-sm flex items-center gap-2">
                                  {comp.name}
                                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${sla < 99.9 ? 'bg-red-50 text-red-600' : 'bg-gray-100 text-gray-500'}`}>
                                    90D SLA: {sla}%
                                  </span>
                                </h4>
                                <p className="text-[10px] text-gray-400">{comp.description}</p>
                              </div>
                              <div className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${
                                compStatus === Severity.OPERATIONAL ? 'bg-emerald-50 text-emerald-600' :
                                compStatus === Severity.DEGRADED ? 'bg-yellow-50 text-yellow-600' : 'bg-red-50 text-red-600'
                              }`}>
                                {compStatus}
                              </div>
                            </div>
                            <UptimeGraph componentId={comp.id} createdAt={comp.createdAt} />
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

