                      value={selRegionId} 
                      onChange={e => { setSelRegionId(e.target.value); setSelServiceId(''); setIncidentForm(p => ({...p, componentId: ''})) }}
                    >
                      <option value="">Select Region...</option>
                      {state.regions.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
