                    <select disabled={!selServiceId} required className="w-full border p-2 rounded-lg text-sm bg-white disabled:bg-gray-100" value={incidentForm.componentId} onChange={e => setIncidentForm({...incidentForm, componentId: e.target.value})}>
                      <option value="">Select Component...</option>
                      {filteredComponents.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
