               {activeForm === 'component' && (
                  <div className="bg-white p-6 rounded-2xl border-2 border-indigo-500 shadow-xl animate-in zoom-in-95">
                    <h3 className="font-bold mb-4">New Component</h3>
                    <input className="w-full border p-3 rounded-xl text-sm mb-4 outline-none focus:border-indigo-500" value={compForm.name} onChange={e => setCompForm({...compForm, name: e.target.value})} placeholder="Component Name" />
                    <button onClick={() => { addComponent(compForm.serviceId, compForm.name, '').then(() => setActiveForm(null)); }} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold">Save</button>
                  </div>
               )}
          </aside>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { AppState, Severity } from './types.ts';
import { api } from './services/api.ts';

interface AppContextType {
  state: AppState;
  isLoading: boolean;
  addRegion: (name: string) => Promise<void>;
  removeRegion: (id: string) => Promise<void>;
  addService: (regionId: string, name: string, description: string) => Promise<void>;
  removeService: (id: string) => Promise<void>;
  addComponent: (serviceId: string, name: string, description: string) => Promise<void>;
  removeComponent: (id: string) => Promise<void>;
  reportIncident: (incident: any) => Promise<void>;
  updateIncident: (id: string, incident: any) => Promise<void>;
  resolveIncident: (incidentId: string) => Promise<void>;
  createAdmin: (user: any) => Promise<void>;
  deleteAdmin: (id: string) => Promise<void>;
  login: (credentials: any) => Promise<void>;
  logout: () => void;
  fetchAdminData: () => Promise<void>;
  calculateSLA: (componentId: string, days?: number) => number;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const TOKEN_KEY = 'voximplant_status_token';
const USER_KEY = 'voximplant_status_user';

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>({
    regions: [],
    services: [],
    components: [],
    incidents: [],
    users: [],
    auditLogs: [],
    isAuthenticated: !!localStorage.getItem(TOKEN_KEY),
    currentUser: localStorage.getItem(USER_KEY) || undefined,
  });
  const [isLoading, setIsLoading] = useState(true);

  const fetchData = useCallback(async () => {
    try {
      const data = await api.getStatus();
      setState(prev => ({ ...prev, ...data }));
    } catch (err) {
      console.error("Failed to fetch status map", err);
    }
  }, []);

  const fetchAdminData = useCallback(async () => {
    if (!localStorage.getItem(TOKEN_KEY)) return;
    try {
      const data = await api.getAdminData();
      setState(prev => ({ ...prev, ...data }));
    } catch (err) {
      console.error("Failed to fetch admin info", err);
    }
  }, []);

  useEffect(() => {
    const init = async () => {
      setIsLoading(true);
      await fetchData();
      if (state.isAuthenticated) await fetchAdminData();
      setIsLoading(false);
    };
    init();
  }, [fetchData, fetchAdminData, state.isAuthenticated]);

  const wrapAction = async (action: () => Promise<any>) => {
    try {
      await action();
      // Ensure we await both fetches to guarantee UI sync
      await Promise.all([
        fetchData(),
        state.isAuthenticated ? fetchAdminData() : Promise.resolve()
      ]);
    } catch (err) {
      console.error("Action Execution Failed:", err);
      throw err;
    }
  };

  const addRegion = (name: string) => wrapAction(() => api.createRegion(name));
  const removeRegion = (id: string) => wrapAction(() => api.deleteRegion(id));
  const addService = (rid: string, n: string, d: string) => wrapAction(() => api.createService(rid, n, d));
  const removeService = (id: string) => wrapAction(() => api.deleteService(id));
  const addComponent = (sid: string, n: string, d: string) => wrapAction(() => api.createComponent(sid, n, d));
  const removeComponent = (id: string) => wrapAction(() => api.deleteComponent(id));

  const reportIncident = (inc: any) => wrapAction(() => api.createIncident(inc));
  const updateIncident = (id: string, inc: any) => wrapAction(() => api.updateIncident(id, inc));
  const resolveIncident = (id: string) => wrapAction(() => api.resolveIncident(id));

  const createAdmin = (u: any) => wrapAction(() => api.createUser(u));
  const deleteAdmin = (id: string) => wrapAction(() => api.deleteUser(id));

  const login = async (cred: any) => {
    const { token, username } = await api.login(cred);
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(USER_KEY, username);
    setState(prev => ({ ...prev, isAuthenticated: true, currentUser: username }));
    await Promise.all([fetchData(), fetchAdminData()]);
  };

  const logout = () => {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
    setState(prev => ({ ...prev, isAuthenticated: false, currentUser: undefined }));
  };

  const calculateSLA = useCallback((componentId: string, days = 90) => {
    const now = Date.now();
    const periodStart = now - (days * 24 * 60 * 60 * 1000);
    const totalMinutes = days * 24 * 60;

    const componentIncidents = state.incidents.filter(i => i.componentId === componentId);
    let totalDowntimeMinutes = 0;

    componentIncidents.forEach(inc => {
      const incStart = Math.max(new Date(inc.startTime).getTime(), periodStart);
      const incEnd = inc.endTime ? new Date(inc.endTime).getTime() : now;

      if (incEnd > periodStart) {
        const durationMs = incEnd - incStart;
        if (durationMs > 0) {
          const durationMinutes = durationMs / (1000 * 60);
          const impactFactor = inc.severity === Severity.OUTAGE ? 1 : 0.5;
          totalDowntimeMinutes += durationMinutes * impactFactor;
        }
      }
    });

    const availability = ((totalMinutes - totalDowntimeMinutes) / totalMinutes) * 100;
    return Math.max(0, Math.min(100, parseFloat(availability.toFixed(3))));
  }, [state.incidents]);

  return (
    <AppContext.Provider value={{
      state, isLoading, addRegion, removeRegion, addService, 
      removeService, addComponent, removeComponent,
      reportIncident, updateIncident, resolveIncident, createAdmin, deleteAdmin, login, logout, fetchAdminData,
      calculateSLA
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import React, { useState, useEffect, useMemo } from 'react';
import { useApp } from '../store.tsx';
import { Severity, Incident } from '../types.ts';
import { geminiService } from '../services/geminiService.ts';

interface AdminDashboardProps {
  onViewPublic?: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onViewPublic }) => {
  const { 
    state, 
    addRegion, removeRegion,
    addService, removeService,
    addComponent, removeComponent,
    reportIncident, updateIncident, resolveIncident, createAdmin, deleteAdmin, logout, fetchAdminData
  } = useApp();

  const [activeTab, setActiveTab] = useState<'reporting' | 'configuration' | 'team' | 'audit'>('reporting');
  const [activeForm, setActiveForm] = useState<'region' | 'service' | 'component' | 'user' | null>(null);
  const [editingIncident, setEditingIncident] = useState<Incident | null>(null);

  const [selRegionId, setSelRegionId] = useState('');
  const [selServiceId, setSelServiceId] = useState('');
  const [incidentForm, setIncidentForm] = useState({ 
    id: '', 
    componentId: '', 
    title: '', 
    severity: Severity.DEGRADED, 
    internalDesc: '',
    startTime: '',
    endTime: ''
  });

  const filteredServices = useMemo(() => state.services.filter(s => s.regionId === selRegionId), [state.services, selRegionId]);
  const filteredComponents = useMemo(() => state.components.filter(c => c.serviceId === selServiceId), [state.components, selServiceId]);

  const [regionForm, setRegionForm] = useState({ name: '' });
  const [serviceForm, setServiceForm] = useState({ regionId: '', name: '', description: '' });
  const [compForm, setCompForm] = useState({ serviceId: '', name: '', description: '' });
  const [userForm, setUserForm] = useState({ username: '', password: '' });

  const [isProcessing, setIsProcessing] = useState(false);
  const [isAiSuggesting, setIsAiSuggesting] = useState(false);

  useEffect(() => {
    if (activeTab === 'team' || activeTab === 'audit') fetchAdminData();
    setActiveForm(null);
    resetFormsState();
  }, [activeTab]);

  const resetFormsState = () => {
    setRegionForm({ name: '' });
    setServiceForm({ regionId: '', name: '', description: '' });
    setCompForm({ serviceId: '', name: '', description: '' });
    setUserForm({ username: '', password: '' });
    setSelRegionId('');
    setSelServiceId('');
    setEditingIncident(null);
    setIncidentForm({ id: '', componentId: '', title: '', severity: Severity.DEGRADED, internalDesc: '', startTime: '', endTime: '' });
  };

  const handleEditIncident = (incident: Incident) => {
    setEditingIncident(incident);
    const component = state.components.find(c => c.id === incident.componentId);
    const service = state.services.find(s => s.id === component?.serviceId);
    const region = state.regions.find(r => r.id === service?.regionId);

    setSelRegionId(region?.id || '');
    setSelServiceId(service?.id || '');
    setIncidentForm({
      id: incident.id,
      componentId: incident.componentId,
      title: incident.title,
      severity: incident.severity,
      internalDesc: incident.description,
      startTime: incident.startTime ? new Date(incident.startTime).toISOString().slice(0, 16) : '',
      endTime: incident.endTime ? new Date(incident.endTime).toISOString().slice(0, 16) : ''
    });
    setActiveTab('reporting');
  };

  const handleSaveIncident = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!incidentForm.componentId) return alert("Select component");
    setIsProcessing(true);
    try {
      const payload = {
        componentId: incidentForm.componentId,
        title: incidentForm.title,
        severity: incidentForm.severity,
        description: incidentForm.internalDesc,
        startTime: incidentForm.startTime ? new Date(incidentForm.startTime).toISOString() : new Date().toISOString(),
        endTime: incidentForm.endTime ? new Date(incidentForm.endTime).toISOString() : null
      };

      if (editingIncident) {
        await updateIncident(editingIncident.id, payload);
      } else {
        await reportIncident(payload);
      }
      resetFormsState();
    } catch (error: any) {
      alert("Failed to save incident: " + error.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleResolve = async (id: string) => {
    if (!confirm("Resolve this incident?")) return;
    setIsProcessing(true);
    try {
      await resolveIncident(id);
    } catch (error: any) {
      alert("Failed to resolve incident: " + error.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleAiSuggest = async () => {
    if (!incidentForm.title || !incidentForm.internalDesc) return alert("Input title/notes");
    setIsAiSuggesting(true);
    try {
      const summary = await geminiService.generateIncidentSummary(incidentForm.title, incidentForm.internalDesc);
      setIncidentForm(prev => ({ ...prev, internalDesc: summary }));
    } catch (err: any) { 
      alert("AI Suggestion failed: " + err.message);
    } finally { 
      setIsAiSuggesting(false); 
    }
  };

  const getActionColor = (type: string) => {
    if (type.startsWith('DELETE')) return 'text-red-600 bg-red-50';
    if (type.startsWith('CREATE')) return 'text-indigo-600 bg-indigo-50';
    if (type.includes('UPDATE')) return 'text-blue-600 bg-blue-50';
    if (type.includes('RESOLVE')) return 'text-emerald-600 bg-emerald-50';
    return 'text-gray-600 bg-gray-50';
  };

  const formatAuditDetails = (details: any) => {
    if (!details) return null;
    if (typeof details === 'string') return details;
    if (details.updated && details.previous) {
      const changes = [];
      if (details.previous.severity !== details.updated.severity) changes.push(`Severity: ${details.previous.severity} → ${details.updated.severity}`);
      if (details.previous.endTime !== details.updated.endTime) changes.push('Modified End Date');
      return changes.length > 0 ? changes.join(' | ') : 'Note update';
    }
    return JSON.stringify(details);
  };

